import { useState, useEffect, useRef } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Menu, X, ChevronDown } from 'lucide-react';

const Navigation = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const [cloudDropdown, setCloudDropdown] = useState(false);
  const [appDropdown, setAppDropdown] = useState(false);
  const [growthDropdown, setGrowthDropdown] = useState(false);
  const [mobileCloudOpen, setMobileCloudOpen] = useState(false);
  const [mobileAppOpen, setMobileAppOpen] = useState(false);
  const [mobileGrowthOpen, setMobileGrowthOpen] = useState(false);
  const dropdownRef = useRef(null);
  const appDropdownRef = useRef(null);
  const growthDropdownRef = useRef(null);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    setIsOpen(false);
    setCloudDropdown(false);
    setAppDropdown(false);
    setGrowthDropdown(false);
    setMobileCloudOpen(false);
    setMobileAppOpen(false);
    setMobileGrowthOpen(false);
  }, [location.pathname]);

  useEffect(() => {
    const handleClickOutside = (e) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setCloudDropdown(false);
      }
      if (appDropdownRef.current && !appDropdownRef.current.contains(e.target)) {
        setAppDropdown(false);
      }
      if (growthDropdownRef.current && !growthDropdownRef.current.contains(e.target)) {
        setGrowthDropdown(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const cloudSubLinks = [
    { name: 'Overview', path: '/managed-cloud-service' },
    { name: 'Cloud Services', path: '/managed-cloud-service/cloud-services' },
    { name: 'CI/CD Automation', path: '/managed-cloud-service/cicd-automation' },
    { name: 'Infrastructure as Code', path: '/managed-cloud-service/infrastructure-as-code' },
    { name: 'Containerization', path: '/managed-cloud-service/containerization' },
    { name: '24/7 Monitoring', path: '/managed-cloud-service/monitoring' },
    { name: 'Database Management', path: '/managed-cloud-service/database-management' },
  ];

  const appSubLinks = [
    { name: 'Overview', path: '/application-development' },
    { name: 'Web Development', path: '/application-development/web-development' },
    { name: 'Mobile App', path: '/application-development/mobile-app' },
  ];

  const growthSubLinks = [
    { name: 'Overview', path: '/digital-growth' },
    { name: 'Branding', path: '/digital-growth/branding' },
    { name: 'Digital Marketing', path: '/digital-growth/digital-marketing' },
    { name: 'Outsourcing', path: '/digital-growth/outsourcing' },
  ];

  const navLinks = [
    { name: 'Home', path: '/' },
    { name: 'AI & ML Services', path: '/ai-ml' },
    { name: 'Managed Cloud Service', path: '/managed-cloud-service', hasDropdown: 'cloud' },
    { name: 'Application Development', path: '/application-development', hasDropdown: 'app' },
    { name: 'Digital Growth & Outsourcing', path: '/digital-growth', hasDropdown: 'growth' },
    { name: 'About Us', path: '/About' },
    { name: 'Blog', path: '/blog' },
    { name: 'Contact', path: '/contact' },
  ];

  const isCloudActive = location.pathname.startsWith('/managed-cloud-service');
  const isAppActive = location.pathname.startsWith('/application-development');
  const isGrowthActive = location.pathname.startsWith('/digital-growth');

  const handleWhatsAppClick = () => {
    const phoneNumber = '+919043765028';
    const message = 'Hello SparkCurv! I would like to know more about your services.';
    const url = `https://wa.me/${phoneNumber.replace(/[^0-9]/g, '')}?text=${encodeURIComponent(message)}`;
    window.open(url, '_blank');
  };

  return (
    <nav
      data-testid="main-navigation"
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
        scrolled ? 'bg-white border-b border-gray-200 shadow-lg' : 'bg-white border-b border-gray-100'
      }`}
    >
      <div className="max-w-full mx-auto px-6 lg:px-12">
        <div className="flex items-center justify-between h-20">
          <Link to="/" className="flex items-center transition-transform hover:scale-105" data-testid="logo-link">
            <img 
              src="/images/logo/sparkcurv-logo.png" 
              alt="SparkCurv Technologies" 
              className="h-25 w-auto object-contain  bg-white rounded"
              style={{ mixBlendMode: 'multiply' }}
            />
          </Link>

          {/* Desktop Nav */}
          <div className="hidden lg:flex items-center space-x-1">
            {navLinks.map((link) => {
              if (link.hasDropdown === 'cloud') {
                return (
                  <div key={link.path} className="relative" ref={dropdownRef}>
                    <button
                      data-testid="nav-link-managed-cloud-service"
                      onClick={() => { setCloudDropdown(!cloudDropdown); setAppDropdown(false); setGrowthDropdown(false); }}
                      className={`px-3 py-2 rounded-lg font-satoshi text-base font-medium transition-all duration-200 whitespace-nowrap inline-flex items-center gap-1 ${
                        isCloudActive
                          ? 'text-[#02028B] bg-blue-50 shadow-sm'
                          : 'text-gray-700 hover:text-[#02028B] hover:bg-blue-50/50'
                      }`}
                    >
                      {link.name}
                      <ChevronDown className={`w-3.5 h-3.5 transition-transform ${cloudDropdown ? 'rotate-180' : ''}`} />
                    </button>
                    {cloudDropdown && (
                      <div className="absolute top-full left-0 mt-2 w-64 bg-white rounded-xl shadow-2xl border border-gray-100 py-2 z-50">
                        {cloudSubLinks.map((sub) => (
                          <Link
                            key={sub.path}
                            to={sub.path}
                            data-testid={`dropdown-${sub.path.split('/').pop() || 'overview'}`}
                            className={`block px-4 py-2.5 text-sm font-medium transition-colors ${
                              location.pathname === sub.path
                                ? 'text-[#02028B] bg-blue-50'
                                : 'text-gray-600 hover:text-[#02028B] hover:bg-blue-50/50'
                            }`}
                          >
                            {sub.name}
                          </Link>
                        ))}
                      </div>
                    )}
                  </div>
                );
              }
              if (link.hasDropdown === 'app') {
                return (
                  <div key={link.path} className="relative" ref={appDropdownRef}>
                    <button
                      data-testid="nav-link-application-development"
                      onClick={() => { setAppDropdown(!appDropdown); setCloudDropdown(false); setGrowthDropdown(false); }}
                      className={`px-3 py-2 rounded-lg font-satoshi text-sm font-medium transition-all duration-200 whitespace-nowrap inline-flex items-center gap-1 ${
                        isAppActive
                          ? 'text-[#02028B] bg-blue-50 shadow-sm'
                          : 'text-gray-700 hover:text-[#02028B] hover:bg-blue-50/50'
                      }`}
                    >
                      {link.name}
                      <ChevronDown className={`w-3.5 h-3.5 transition-transform ${appDropdown ? 'rotate-180' : ''}`} />
                    </button>
                    {appDropdown && (
                      <div className="absolute top-full left-0 mt-2 w-56 bg-white rounded-xl shadow-2xl border border-gray-100 py-2 z-50">
                        {appSubLinks.map((sub) => (
                          <Link
                            key={sub.path}
                            to={sub.path}
                            data-testid={`dropdown-app-${sub.path.split('/').pop() || 'overview'}`}
                            className={`block px-4 py-2.5 text-sm font-medium transition-colors ${
                              location.pathname === sub.path
                                ? 'text-[#02028B] bg-blue-50'
                                : 'text-gray-600 hover:text-[#02028B] hover:bg-blue-50/50'
                            }`}
                          >
                            {sub.name}
                          </Link>
                        ))}
                      </div>
                    )}
                  </div>
                );
              }
              if (link.hasDropdown === 'growth') {
                return (
                  <div key={link.path} className="relative" ref={growthDropdownRef}>
                    <button
                      data-testid="nav-link-digital-growth"
                      onClick={() => { setGrowthDropdown(!growthDropdown); setCloudDropdown(false); setAppDropdown(false); }}
                      className={`px-3 py-2 rounded-lg font-satoshi text-sm font-medium transition-all duration-200 whitespace-nowrap inline-flex items-center gap-1 ${
                        isGrowthActive
                          ? 'text-[#02028B] bg-blue-50 shadow-sm'
                          : 'text-gray-700 hover:text-[#02028B] hover:bg-blue-50/50'
                      }`}
                    >
                      {link.name}
                      <ChevronDown className={`w-3.5 h-3.5 transition-transform ${growthDropdown ? 'rotate-180' : ''}`} />
                    </button>
                    {growthDropdown && (
                      <div className="absolute top-full left-0 mt-2 w-56 bg-white rounded-xl shadow-2xl border border-gray-100 py-2 z-50">
                        {growthSubLinks.map((sub) => (
                          <Link
                            key={sub.path}
                            to={sub.path}
                            data-testid={`dropdown-growth-${sub.path.split('/').pop() || 'overview'}`}
                            className={`block px-4 py-2.5 text-sm font-medium transition-colors ${
                              location.pathname === sub.path
                                ? 'text-[#02028B] bg-blue-50'
                                : 'text-gray-600 hover:text-[#02028B] hover:bg-blue-50/50'
                            }`}
                          >
                            {sub.name}
                          </Link>
                        ))}
                      </div>
                    )}
                  </div>
                );
              }
              return (
                <Link
                  key={link.path}
                  to={link.path}
                  data-testid={`nav-link-${link.name.toLowerCase().replace(/\s+/g, '-')}`}
                  className={`px-3 py-2 rounded-lg font-satoshi text-sm font-medium transition-all duration-200 whitespace-nowrap ${
                    location.pathname === link.path
                      ? 'text-[#02028B] bg-blue-50 shadow-sm'
                      : 'text-gray-700 hover:text-[#02028B] hover:bg-blue-50/50'
                  }`}
                >
                  {link.name}
                </Link>
              );
            })}
            <button
              onClick={handleWhatsAppClick}
              data-testid="whatsapp-header-button"
              className="ml-4 w-12 h-12 rounded-full bg-gradient-to-r from-[#25D366] to-[#20BA5A] text-white hover:shadow-lg hover:shadow-green-500/30 transition-all duration-200 flex items-center justify-center transform hover:scale-110"
              aria-label="Contact us on WhatsApp"
            >
              <svg className="w-6 h-6" viewBox="0 0 24 24" fill="currentColor">
