      {isOpen && (
        <div data-testid="mobile-menu" className="lg:hidden bg-white border-t border-gray-200 shadow-lg animate-slide-down max-h-[80vh] overflow-y-auto">
          <div className="px-6 py-4 space-y-2">
            {navLinks.map((link) => {
