                return (
                  <div key={link.path}>
                    <button
                      onClick={() => setMobileCloudOpen(!mobileCloudOpen)}
                      data-testid="mobile-nav-managed-cloud"
                      className={`w-full flex items-center justify-between px-4 py-3 rounded-lg font-satoshi font-medium transition-colors ${
                        isCloudActive ? 'text-[#02028B] bg-blue-50' : 'text-gray-700 hover:text-[#02028B] hover:bg-blue-50/50'
                      }`}
                    >
                      <span>{link.name}</span>
                      <ChevronDown className={`w-4 h-4 transition-transform ${mobileCloudOpen ? 'rotate-180' : ''}`} />
                    </button>
                    {mobileCloudOpen && (
                      <div className="ml-4 mt-1 space-y-1 border-l-2 border-blue-100 pl-4">
                        {cloudSubLinks.map((sub) => (
                          <Link
                            key={sub.path}
                            to={sub.path}
                            onClick={() => setIsOpen(false)}
                            className={`block px-4 py-2.5 rounded-lg text-sm font-medium transition-colors ${
                              location.pathname === sub.path
                                ? 'text-[#02028B] bg-blue-50'
                                : 'text-gray-600 hover:text-[#02028B] hover:bg-blue-50/50'
                            }`}
                          >
                            {sub.name}
                          </Link>
                        ))}
                      </div>
                    )}
                  </div>
                );
              }
              if (link.hasDropdown === 'app') {
                return (
                  <div key={link.path}>
                    <button
                      onClick={() => setMobileAppOpen(!mobileAppOpen)}
                      data-testid="mobile-nav-app-dev"
                      className={`w-full flex items-center justify-between px-4 py-3 rounded-lg font-satoshi font-medium transition-colors ${
                        isAppActive ? 'text-[#02028B] bg-blue-50' : 'text-gray-700 hover:text-[#02028B] hover:bg-blue-50/50'
                      }`}
                    >
                      <span>{link.name}</span>
                      <ChevronDown className={`w-4 h-4 transition-transform ${mobileAppOpen ? 'rotate-180' : ''}`} />
                    </button>
                    {mobileAppOpen && (
                      <div className="ml-4 mt-1 space-y-1 border-l-2 border-blue-100 pl-4">
                        {appSubLinks.map((sub) => (
                          <Link
                            key={sub.path}
                            to={sub.path}
                            onClick={() => setIsOpen(false)}
                            className={`block px-4 py-2.5 rounded-lg text-sm font-medium transition-colors ${
                              location.pathname === sub.path
                                ? 'text-[#02028B] bg-blue-50'
                                : 'text-gray-600 hover:text-[#02028B] hover:bg-blue-50/50'
                            }`}
                          >
                            {sub.name}
                          </Link>
                        ))}
                      </div>
                    )}
                  </div>
                );
              }
              if (link.hasDropdown === 'growth') {
                return (
                  <div key={link.path}>
                    <button
                      onClick={() => setMobileGrowthOpen(!mobileGrowthOpen)}
                      data-testid="mobile-nav-digital-growth"
                      className={`w-full flex items-center justify-between px-4 py-3 rounded-lg font-satoshi font-medium transition-colors ${
                        isGrowthActive ? 'text-[#02028B] bg-blue-50' : 'text-gray-700 hover:text-[#02028B] hover:bg-blue-50/50'
                      }`}
                    >
                      <span>{link.name}</span>
                      <ChevronDown className={`w-4 h-4 transition-transform ${mobileGrowthOpen ? 'rotate-180' : ''}`} />
                    </button>
                    {mobileGrowthOpen && (
                      <div className="ml-4 mt-1 space-y-1 border-l-2 border-blue-100 pl-4">
                        {growthSubLinks.map((sub) => (
                          <Link
                            key={sub.path}
                            to={sub.path}
                            onClick={() => setIsOpen(false)}
                            className={`block px-4 py-2.5 rounded-lg text-sm font-medium transition-colors ${
                              location.pathname === sub.path
                                ? 'text-[#02028B] bg-blue-50'
                                : 'text-gray-600 hover:text-[#02028B] hover:bg-blue-50/50'
                            }`}
                          >
                            {sub.name}
                          </Link>
                        ))}
                      </div>
                    )}
                  </div>
                );
              }
              return (
                <Link
                  key={link.path}
                  to={link.path}
                  onClick={() => setIsOpen(false)}
                  data-testid={`mobile-nav-link-${link.name.toLowerCase().replace(/\s+/g, '-')}`}
                  className={`block px-4 py-3 rounded-lg font-satoshi font-medium transition-colors ${
                    location.pathname === link.path
                      ? 'text-[#02028B] bg-blue-50'
                      : 'text-gray-700 hover:text-[#02028B] hover:bg-blue-50/50'
                  }`}
                >
                  {link.name}
                </Link>
              );
            })}
            <button
              onClick={() => { handleWhatsAppClick(); setIsOpen(false); }}
              data-testid="mobile-whatsapp-button"
              className="w-full bg-gradient-to-r from-[#25D366] to-[#20BA5A] text-white hover:shadow-lg transition-all rounded-lg px-5 py-3 font-medium inline-flex items-center justify-center space-x-2"
            >
              <svg className="w-5 h-5" viewBox="0 0 24 24" fill="currentColor">
                <path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413Z"/>
              </svg>
              <span>WhatsApp</span>
            </button>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navigation;
